const Checkout = ({ cart, setCart, currentUser, loadProducts, setCurrentSection }) => {
  const [paymentMethod, setPaymentMethod] = useState('card');
  const [shippingAddress, setShippingAddress] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);

  const total = cart.reduce((sum, item) => sum + (parseFloat(item.price) * item.quantity), 0);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsProcessing(true);

    try {
      const orderData = {
        user_id: currentUser.id,
        total: total,
        payment_method: paymentMethod,
        shipping_address: shippingAddress,
        items: cart.map(item => ({
          product_id: item.id,
          quantity: item.quantity,
          price: item.price
        }))
      };

      const response = await axios.post(`${API_BASE}/orders`, orderData);

      if (response.data.success) {
        if (paymentMethod === 'card') {
          // Simulate payment gateway redirect
          window.location.href = `${window.location.origin}${window.location.pathname}?status=success&tx_ref=${response.data.orderId}`;
        } else {
          alert('Order placed successfully! You will pay on delivery.');
          setCart([]);
          loadProducts();
          setCurrentSection('orders');
        }
      } else {
        alert('Order failed. Please try again.');
      }
    } catch (error) {
      console.error('Checkout error:', error);
      alert('Order failed. Please try again.');
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <section className="section active">
      <div className="container">
        <h2>Checkout</h2>
        <div className="checkout-container">
          <div className="order-summary">
            <h3>Order Summary</h3>
            {cart.map(item => (
              <div key={item.id} className="checkout-item">
                <span>{item.name} x {item.quantity}</span>
                <span>{(parseFloat(item.price) * item.quantity).toFixed(2)} ETB</span>
              </div>
            ))}
            <div className="checkout-total">
              <strong>Total: {total.toFixed(2)} ETB</strong>
            </div>
          </div>

          <form onSubmit={handleSubmit} className="checkout-form">
            <div className="form-group">
              <label>Payment Method:</label>
              <select 
                value={paymentMethod} 
                onChange={(e) => setPaymentMethod(e.target.value)}
                required
              >
                <option value="card">Credit/Debit Card</option>
                <option value="cod">Cash on Delivery</option>
              </select>
            </div>

            <div className="form-group">
              <label>Shipping Address:</label>
              <textarea
                value={shippingAddress}
                onChange={(e) => setShippingAddress(e.target.value)}
                placeholder="Enter your full address"
                required
                rows="4"
              />
            </div>

            <button type="submit" className="btn-primary" disabled={isProcessing}>
              {isProcessing ? 'Processing...' : 'Place Order'}
            </button>
          </form>
        </div>
      </div>
    </section>
  );
};

