const UserProfile = ({ currentUser, setCurrentUser }) => {
  const [formData, setFormData] = useState({
    name: currentUser.name || '',
    email: currentUser.email || '',
    currentPassword: '',
    newPassword: '',
    confirmPassword: ''
  });

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (formData.newPassword && formData.newPassword !== formData.confirmPassword) {
      alert('New passwords do not match');
      return;
    }

    try {
      const updateData = {
        userId: currentUser.id,
        name: formData.name,
        email: formData.email
      };

      if (formData.newPassword) {
        updateData.currentPassword = formData.currentPassword;
        updateData.newPassword = formData.newPassword;
      }

      const response = await axios.put(`${API_BASE}/auth/profile`, updateData);

      if (response.data.success) {
        alert('Profile updated successfully!');
        const updatedUser = { ...currentUser, name: formData.name, email: formData.email };
        setCurrentUser(updatedUser);
        localStorage.setItem('currentUser', JSON.stringify(updatedUser));
        setFormData({ ...formData, currentPassword: '', newPassword: '', confirmPassword: '' });
      } else {
        alert(response.data.message || 'Profile update failed');
      }
    } catch (error) {
      console.error('Profile update error:', error);
      alert('Profile update failed. Please try again.');
    }
  };

  return (
    <section className="section active">
      <div className="container">
        <h2>My Profile</h2>
        <form onSubmit={handleSubmit} className="profile-form">
          <div className="form-group">
            <label>Name:</label>
            <input
              type="text"
              name="name"
              value={formData.name}
              onChange={handleInputChange}
              required
            />
          </div>

          <div className="form-group">
            <label>Email:</label>
            <input
              type="email"
              name="email"
              value={formData.email}
              onChange={handleInputChange}
              required
            />
          </div>

          <h3>Change Password (Optional)</h3>

          <div className="form-group">
            <label>Current Password:</label>
            <input
              type="password"
              name="currentPassword"
              value={formData.currentPassword}
              onChange={handleInputChange}
            />
          </div>

          <div className="form-group">
            <label>New Password:</label>
            <input
              type="password"
              name="newPassword"
              value={formData.newPassword}
              onChange={handleInputChange}
            />
          </div>

          <div className="form-group">
            <label>Confirm New Password:</label>
            <input
              type="password"
              name="confirmPassword"
              value={formData.confirmPassword}
              onChange={handleInputChange}
            />
          </div>

          <button type="submit" className="btn-primary">Update Profile</button>
        </form>
      </div>
    </section>
  );
};

const Admin = ({ products, loadProducts }) => {
  const [activeTab, setActiveTab] = useState('products');
  const [users, setUsers] = useState([]);
  const [orders, setOrders] = useState([]);
  const [salesReport, setSalesReport] = useState(null);
  const [productForm, setProductForm] = useState({
    name: '', description: '', price: '', stock: '', category_id: '1', image_url: ''
  });
  const [editingProduct, setEditingProduct] = useState(null);

  useEffect(() => {
    if (activeTab === 'users') loadUsers();
    if (activeTab === 'orders') loadOrders();
    if (activeTab === 'reports') loadSalesReport();
  }, [activeTab]);

  const loadUsers = async () => {
    try {
      const response = await axios.get(`${API_BASE}/admin/users`);
      setUsers(response.data);
    } catch (error) {
      console.error('Error loading users:', error);
    }
  };

  const loadOrders = async () => {
    try {
      const response = await axios.get(`${API_BASE}/admin/orders`);
      setOrders(response.data);
    } catch (error) {
      console.error('Error loading orders:', error);
    }
  };

  const loadSalesReport = async () => {
    try {
      const response = await axios.get(`${API_BASE}/admin/sales-report`);
      setSalesReport(response.data);
    } catch (error) {
      console.error('Error loading sales report:', error);
    }
  };

  const handleProductSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingProduct) {
        await axios.put(`${API_BASE}/admin/products/${editingProduct.id}`, productForm);
        alert('Product updated successfully!');
      } else {
        await axios.post(`${API_BASE}/admin/products`, productForm);
        alert('Product added successfully!');
      }
      setProductForm({ name: '', description: '', price: '', stock: '', category_id: '1', image_url: '' });
      setEditingProduct(null);
      loadProducts();
    } catch (error) {
      console.error('Error saving product:', error);
      alert('Error saving product');
    }
  };

  const editProduct = (product) => {
    setProductForm(product);
    setEditingProduct(product);
  };

  const deleteProduct = async (productId) => {
    if (confirm('Are you sure you want to delete this product?')) {
      try {
        await axios.delete(`${API_BASE}/admin/products/${productId}`);
        alert('Product deleted successfully!');
        loadProducts();
      } catch (error) {
        console.error('Error deleting product:', error);
        alert('Error deleting product');
      }
    }
  };

  const updateOrderStatus = async (orderId, status) => {
    try {
      await axios.put(`${API_BASE}/admin/orders/${orderId}/status`, { status });
      alert('Order status updated!');
      loadOrders();
    } catch (error) {
      console.error('Error updating order status:', error);
      alert('Error updating order status');
    }
  };

  return (
    <section className="section active">
      <div className="container">
        <h2>Admin Dashboard</h2>

        <div className="admin-tabs">
          <button 
            className={activeTab === 'products' ? 'active' : ''} 
            onClick={() => setActiveTab('products')}
          >
            Products
          </button>
          <button 
            className={activeTab === 'users' ? 'active' : ''} 
            onClick={() => setActiveTab('users')}
          >
            Users
          </button>
          <button 
            className={activeTab === 'orders' ? 'active' : ''} 
            onClick={() => setActiveTab('orders')}
          >
            Orders
          </button>
          <button 
            className={activeTab === 'reports' ? 'active' : ''} 
            onClick={() => setActiveTab('reports')}
          >
            Reports
          </button>
        </div>

        {activeTab === 'products' && (
          <div className="admin-content">
            <h3>{editingProduct ? 'Edit Product' : 'Add New Product'}</h3>
            <form onSubmit={handleProductSubmit} className="product-form">
              <input
                type="text"
                placeholder="Product Name"
                value={productForm.name}
                onChange={(e) => setProductForm({...productForm, name: e.target.value})}
                required
              />
              <textarea
                placeholder="Description"
                value={productForm.description}
                onChange={(e) => setProductForm({...productForm, description: e.target.value})}
                required
              />
              <input
                type="number"
                step="0.01"
                placeholder="Price"
                value={productForm.price}
                onChange={(e) => setProductForm({...productForm, price: e.target.value})}
                required
              />
              <input
                type="number"
                placeholder="Stock"
                value={productForm.stock}
                onChange={(e) => setProductForm({...productForm, stock: e.target.value})}
                required
              />
              <select
                value={productForm.category_id}
                onChange={(e) => setProductForm({...productForm, category_id: e.target.value})}
                required
              >
                <option value="1">Electronics</option>
                <option value="2">Clothing</option>
                <option value="3">Home</option>
              </select>
              <input
                type="url"
                placeholder="Image URL"
                value={productForm.image_url}
                onChange={(e) => setProductForm({...productForm, image_url: e.target.value})}
                required
              />
              <button type="submit" className="btn-primary">
                {editingProduct ? 'Update Product' : 'Add Product'}
              </button>
              {editingProduct && (
                <button 
                  type="button" 
                  onClick={() => {
                    setEditingProduct(null);
                    setProductForm({ name: '', description: '', price: '', stock: '', category_id: '1', image_url: '' });
                  }}
                  className="btn-secondary"
                >
                  Cancel
                </button>
              )}
            </form>

            <h3>Existing Products</h3>
            <div className="products-table">
              {products.map(product => (
                <div key={product.id} className="product-row">
                  <div className="product-info">
                    <h4>{product.name}</h4>
                    <p>Price: {parseFloat(product.price).toFixed(2)} ETB</p>
                    <p>Stock: {product.stock}</p>
                  </div>
                  <div className="product-actions">
                    <button onClick={() => editProduct(product)} className="btn-secondary">Edit</button>
                    <button onClick={() => deleteProduct(product.id)} className="btn-danger">Delete</button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'users' && (
          <div className="admin-content">
            <h3>Users</h3>
            <div className="users-table">
              {users.map(user => (
                <div key={user.id} className="user-row">
                  <div className="user-info">
                    <h4>{user.name}</h4>
                    <p>Email: {user.email}</p>
                    <p>Role: {user.role}</p>
                    <p>Joined: {new Date(user.created_at).toLocaleDateString()}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'orders' && (
          <div className="admin-content">
            <h3>Orders</h3>
            <div className="orders-table">
              {orders.map(order => (
                <div key={order.id} className="order-row">
                  <div className="order-info">
                    <h4>Order #{order.id}</h4>
                    <p>Customer: {order.customer_name} ({order.customer_email})</p>
                    <p>Total: {parseFloat(order.total).toFixed(2)} ETB</p>
                    <p>Status: {order.status}</p>
                    <p>Items: {order.items}</p>
                    <p>Date: {new Date(order.created_at).toLocaleDateString()}</p>
                  </div>
                  <div className="order-actions">
                    <select 
                      value={order.status} 
                      onChange={(e) => updateOrderStatus(order.id, e.target.value)}
                    >
                      <option value="pending">Pending</option>
                      <option value="shipped">Shipped</option>
                      <option value="delivered">Delivered</option>
                      <option value="cancelled">Cancelled</option>
                    </select>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'reports' && (
          <div className="admin-content">
            <h3>Sales Report (Last 30 Days)</h3>
            {salesReport && (
              <div className="sales-summary">
                <div className="summary-card">
                  <h4>Total Orders</h4>
                  <p>{salesReport.summary.total_orders}</p>
                </div>
                <div className="summary-card">
                  <h4>Total Revenue</h4>
                  <p>{parseFloat(salesReport.summary.total_revenue).toFixed(2)} ETB</p>
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </section>
  );
};

const getCategoryIcon = (categoryName) => {
  const icons = {
    'Electronics': 'laptop',
    'Clothing': 'tshirt',
    'Home': 'home'
  };
  return icons[categoryName] || 'box';
};

export default App;
